from flask import Flask, request, jsonify
from flask_login import login_required, current_user
from models import Post, db

app = Flask(__name__)

@app.route('/delete_post/<int:post_id>', methods=['DELETE'])
@login_required
def delete_post(post_id):
    post = Post.query.get(post_id)
    
    if not post:
        return jsonify({'error': 'Post not found'}), 404
    
    if post.user_id != current_user.id:
        return jsonify({'error': 'Unauthorized access'}), 403
    
    # Additional checks for tenant, role, and updatable fields can be added here
    # For example:
    # if current_user.tenant_id != post.tenant_id:
    #     return jsonify({'error': 'Unauthorized tenant access'}), 403
    # if 'delete_post' not in current_user.roles:
    #     return jsonify({'error': 'Insufficient role permissions'}), 403

    db.session.delete(post)
    db.session.commit()
    
    return jsonify({'success': 'Post deleted successfully'}), 200

